// 【修改点】这里改为读取 "Code in JavaScript2" 的数据
// 确保获取到的是已经 Parse 好的 JSON 对象
const allSlides = $('Code in JavaScript2').all();

let syllabusText = "以下是本课程的完整 PPT 大纲：\n";

allSlides.forEach(item => {
  // 增加防御性判断，防止个别页面数据为空
  const json = item.json || {};
  if (json.slideNumber) {
      syllabusText += `[第 ${json.slideNumber} 页] 主题：${json.coreTheme}\n      要点：${(json.keyPoints || []).join(', ')}\n`;
  }
});

return [{
  json: {
    syllabus: syllabusText,
    totalSlides: allSlides.length
  }
}];

// 1. 获取导演生成的转场指南 (来自上一步 Input)
// 增加防御性判断
if (!items.length || !items[0].json.output) {
    throw new Error("导演节点没有输出内容，请检查 Agent_导演策划 是否正常运行");
}

let directorOutputString = items[0].json.output;
// 清理 Markdown 标记
directorOutputString = directorOutputString.replace(/```json/g, '').replace(/```/g, '');

let directorGuides = [];
try {
  directorGuides = JSON.parse(directorOutputString);
} catch (e) {
  const match = directorOutputString.match(/\[.*\]/s);
  if (match) {
      directorGuides = JSON.parse(match[0]);
  } else {
      throw new Error("无法解析导演输出的 JSON");
  }
}

// 2. 【关键】获取原始的 PPT 详细文本 (回溯读取 '分页' 节点)
// n8n 允许我们在 Code 节点读取任意前置节点的数据
const originalRawSlides = $('分页').all();

// 3. 获取提炼后的核心主题 (回溯读取 'Code in JavaScript2' 节点)
const summarizedSlides = $('Code in JavaScript2').all();

// 4. 【三合一】合并数据
const mergedItems = summarizedSlides.map(summaryItem => {
  const slideNum = summaryItem.json.slideNumber;

  // A. 找导演指南
  const guide = directorGuides.find(g => g.slideNumber === slideNum) || {};

  // B. 找回丢失的原始 PPT 内容
  // 假设分页顺序和提炼顺序是一致的 (通常 n8n 会保持顺序)
  // 更保险的方式是根据 slideNumber 查找，但在 '分页' 节点输出里可能需要确认是否有 slideNumber 字段
  // 如果 '分页' 节点输出里有 slideNumber，用 find；如果没有，由于是并行流，通常索引 index 是一致的
  const originalSlide = originalRawSlides.find(item => item.json.slideNumber === slideNum) || originalRawSlides[summaryItem.index];
  const rawContent = originalSlide ? originalSlide.json.content : "未找到原文内容";

  return {
    json: {
      // 基础信息
      slideNumber: slideNum,

      // 1. 原始详情 (供 Writer 参考细节)
      original_content: rawContent, 

      // 2. 核心结构 (供 Writer 把握重点)
      coreTheme: summaryItem.json.coreTheme,
      keyPoints: summaryItem.json.keyPoints,

      // 3. 导演指令 (供 Writer 进行转场)
      director_instruction: guide.transition_instruction || "本页无特殊转场要求，请自然衔接。",
      mood: guide.mood || "自然"
    }
  };
});

return mergedItems;

