={{ (() => {
  // 1. 获取 Webhook 节点的数据
  // 注意：main.py 发送的是 POST JSON，所以数据通常在 body 中
  const webhookData = $('Webhook').first().json;

  // 2. 健壮地获取 task_id
  // 优先查找 body 中的 task_id (main.py 的发送方式)
  // 其次查找 query 中的 task_id (防止以后你改用 GET 请求)
  const taskId = (webhookData.body && webhookData.body.task_id) || 
                 (webhookData.query && webhookData.query.task_id) ||
                 (webhookData.task_id); // 有些版本的 n8n 会直接解析在根目录

  // 3. 调试日志 (可选，如果 n8n 支持 console.log)
  // console.log("Extracted Task ID:", taskId);

  if (!taskId) {
      // 如果真的取不到，为了不让流程报错挂起，可以返回一个假的 ID 或者抛出明确错误
      // 这里抛出错误会让 n8n 停止执行，方便你排查
      throw new Error("无法从 Webhook 获取 task_id，请检查 trigger 数据结构");
  }

  // 4. 返回给 HTTP Request 节点发送的数据
  return {
    "task_id": taskId, 
    "status": "paginated", // <--- 注意：不同的汇报节点要改这里的 status 字段 (如: syllabus_ready, director_finished)
    "data": {
      "total_slides": $('分页').all().length // <--- 注意：这里根据不同节点传不同数据
    }
  };
})() }}

